"""Single-source evidence-first admin UI served by the backend runtime."""

ENTERPRISE_ADMIN_HTML = r"""<!doctype html>
<html lang="de"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Sovereign Enterprise Admin</title><style>
:root{color-scheme:dark;--bg:#080b10;--panel:#111722;--line:#293246;--text:#f4f7fb;--muted:#9aa8bd;--ok:#55d88b;--warn:#ffc857;--bad:#ff6b6b;--accent:#6ea8fe}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:15px system-ui,sans-serif}main{max-width:1100px;margin:auto;padding:20px}.top{display:flex;gap:12px;align-items:center;flex-wrap:wrap}.top h1{font-size:22px;margin-right:auto}input,button,select{min-height:48px;border-radius:9px;border:1px solid var(--line);background:var(--panel);color:var(--text);padding:0 14px}input{min-width:280px}button{cursor:pointer;font-weight:700}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px;margin-top:16px}.card{background:var(--panel);border:1px solid var(--line);border-radius:12px;padding:16px}.card h2{font-size:15px;margin:0 0 10px}.value{font-size:28px;font-weight:800}.muted{color:var(--muted)}.ok{color:var(--ok)}.blocked{color:var(--bad)}.warn{color:var(--warn)}table{width:100%;border-collapse:collapse;margin-top:10px}th,td{text-align:left;padding:10px;border-bottom:1px solid var(--line);vertical-align:top}code{word-break:break-all}.hidden{display:none}.notice{margin-top:12px;padding:12px;border:1px solid var(--line);border-radius:9px}.actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}@media(max-width:650px){main{padding:12px}.top input{width:100%;min-width:0}th:nth-child(3),td:nth-child(3){display:none}}
</style></head><body><main>
<div class="top"><h1>Sovereign Enterprise Admin</h1><input id="key" type="password" placeholder="Admin API Key" autocomplete="off"><button onclick="login()">Anmelden</button><button id="logout" class="hidden" onclick="logout()">Abmelden</button></div>
<div id="message" class="notice muted">Diese Oberfläche zeigt ausschließlich live gelesene Enterprise-Runtime-, Integrations-, pgvector-, Milvus- und Evidence-Daten.</div>
<section id="content" class="hidden"><div class="actions"><button onclick="refreshAll()">Aktualisieren</button><button onclick="runCanary('readiness')">Readiness-Canary</button></div><div id="summary" class="grid"></div><div class="card" style="margin-top:12px"><h2>Integrationen</h2><div id="integrations"></div></div><div class="card" style="margin-top:12px"><h2>Persistierte Evidence</h2><div id="evidence"></div></div></section>
<script>
let token='';const q=id=>document.getElementById(id);function headers(){return{'Authorization':'Bearer '+token,'Content-Type':'application/json'}}function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}async function api(path,opt={}){const r=await fetch(path,{...opt,headers:{...headers(),...(opt.headers||{})}});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.error||d.message||('HTTP '+r.status));return d}async function login(){token=q('key').value.trim();if(!token)return;try{await api('/api/admin/ping');q('content').classList.remove('hidden');q('logout').classList.remove('hidden');q('key').value='';await refreshAll()}catch(e){token='';q('message').textContent='Anmeldung fehlgeschlagen: '+e.message;q('message').className='notice blocked'}}function logout(){token='';q('content').classList.add('hidden');q('logout').classList.add('hidden');q('message').textContent='Abgemeldet.';q('message').className='notice muted'}async function refreshAll(){try{q('message').textContent='Live-Daten werden gelesen…';q('message').className='notice muted';const[o,e]=await Promise.all([api('/api/admin/platform/v1/overview'),api('/api/admin/platform/v1/evidence?limit=30')]);render(o,e);q('message').textContent='Live-Readback bestätigt. Keine UI-erzeugte Wahrheit.';q('message').className='notice ok'}catch(err){q('message').textContent='Readback fehlgeschlagen: '+err.message;q('message').className='notice blocked'}}function metric(label,value,cls=''){return`<div class="card"><h2>${esc(label)}</h2><div class="value ${cls}">${esc(value)}</div></div>`}function render(o,e){const s=o.statistics||{};const vector=s.vectors||s.vectorMemory||{};const milvus=vector.milvus||s.milvus||{};const pg=vector.pgvector||s.pgvector||{};q('summary').innerHTML=[metric('Runtime',o.status||'unknown',o.status==='verified'?'ok':'blocked'),metric('Revision',o.runtime?.revision||o.runtime?.sourceRevision||'unverified'),metric('pgvector',pg.total??pg.count??s.knowledgeVectors??'—'),metric('Milvus indexed',milvus.indexed??'—'),metric('Milvus pending',milvus.pending??'—',Number(milvus.pending)>0?'warn':''),metric('Milvus blocked',milvus.blocked??'—',Number(milvus.blocked)>0?'blocked':'')].join('');const ints=o.integrations||[];q('integrations').innerHTML=ints.length?`<table><thead><tr><th>Name</th><th>Status</th><th>Evidence</th></tr></thead><tbody>${ints.map(i=>`<tr><td>${esc(i.name||i.id)}</td><td class="${i.status==='verified'?'ok':'blocked'}">${esc(i.status)}</td><td><code>${esc(i.evidenceSha256||i.blocker||i.detail||'')}</code></td></tr>`).join('')}</tbody></table>`:'Keine Integrationsdaten.';const rows=e.evidence||[];q('evidence').innerHTML=rows.length?`<table><thead><tr><th>Zeit</th><th>Scope</th><th>SHA-256</th></tr></thead><tbody>${rows.map(r=>`<tr><td>${esc(r.observedAt||r.createdAt||'')}</td><td>${esc(r.scope||r.status||'')}</td><td><code>${esc(r.evidenceSha256||'')}</code></td></tr>`).join('')}</tbody></table>`:'Keine Evidence-Einträge.'}async function runCanary(scope){try{const d=await api('/api/admin/platform/v1/canaries',{method:'POST',body:JSON.stringify({scope,confirmed:true})});q('message').textContent='Canary '+scope+': '+(d.status||'abgeschlossen');q('message').className='notice '+(d.ok?'ok':'blocked');await refreshAll()}catch(e){q('message').textContent='Canary fehlgeschlagen: '+e.message;q('message').className='notice blocked'}}
</script></main></body></html>"""
